(function(){
  'use strict';
  var root = document.getElementById('ib-quiz-single');
  if (!root) return;
  if (root.getAttribute('data-qs-ready') === '1') return;
  root.setAttribute('data-qs-ready', '1');

  var options = Array.prototype.slice.call(root.querySelectorAll('.ek-option'));
  var feedback = root.querySelector('#quiz-single-feedback');
  var resetBtn = root.querySelector('#quiz-single-reset');
  var answered = false;

  var TEXT_OK = '<strong>Верно! 🎉</strong> Python читает каскад сверху вниз и выполняет только первую ветку с истинным условием — здесь это «if score >= 50», поэтому напечатается «Зачёт». Остальные elif и else он просто пропускает, даже если их условия тоже истинны.';
  var TEXT_ERR = '<strong>Пока нет.</strong> Python проходит каскад сверху вниз и выполняет только первую ветку, где условие истинно, — остальное пропускает без всякой ошибки. В примере первым сработает «if score >= 50», поэтому напечатается только «Зачёт». Правильный ответ подсвечен зелёным.';

  function pick(e){
    if (answered) return;
    answered = true;
    var chosen = e.currentTarget;
    var right = chosen.getAttribute('data-correct') === 'true';
    for (var i = 0; i < options.length; i++){
      options[i].disabled = true;
      if (options[i].getAttribute('data-correct') === 'true'){
        options[i].classList.add('is-correct');
      }
    }
    if (!right){
      chosen.classList.add('is-wrong');
    }
    feedback.className = 'ek-feedback is-on ' + (right ? 'ek-feedback--ok' : 'ek-feedback--err');
    feedback.innerHTML = right ? TEXT_OK : TEXT_ERR;
    resetBtn.disabled = false;
  }

  function reset(){
    answered = false;
    for (var i = 0; i < options.length; i++){
      options[i].disabled = false;
      options[i].classList.remove('is-selected', 'is-correct', 'is-wrong');
    }
    feedback.className = 'ek-feedback';
    feedback.innerHTML = '';
    resetBtn.disabled = true;
  }

  for (var j = 0; j < options.length; j++){
    options[j].addEventListener('click', pick);
  }
  resetBtn.addEventListener('click', reset);
})();

