(function () {
  'use strict';
  var root = document.getElementById('ib-quiz-multi');
  if (!root) return;
  if (root.getAttribute('data-quiz-multi-init') === '1') return;
  root.setAttribute('data-quiz-multi-init', '1');

  var options = Array.prototype.slice.call(root.querySelectorAll('.ek-option'));
  var btnCheck = root.querySelector('#quiz-multi-check');
  var btnReset = root.querySelector('#quiz-multi-reset');
  var feedback = root.querySelector('#quiz-multi-feedback');
  var counter = root.querySelector('#quiz-multi-count');
  var TOTAL_CORRECT = options.filter(function (o) {
    return o.getAttribute('data-correct') === '1';
  }).length;
  var isChecked = false;

  function countSelected() {
    return options.filter(function (o) {
      return o.classList.contains('is-selected');
    }).length;
  }

  function syncControls() {
    var n = countSelected();
    counter.textContent = 'Выбрано: ' + n;
    counter.classList.toggle('is-active', n > 0);
    if (!isChecked) {
      btnCheck.disabled = n === 0;
      btnReset.disabled = n === 0;
    }
  }

  options.forEach(function (opt) {
    opt.addEventListener('click', function () {
      if (isChecked) return;
      var on = opt.classList.toggle('is-selected');
      opt.setAttribute('aria-pressed', on ? 'true' : 'false');
      syncControls();
    });
  });

  btnCheck.addEventListener('click', function () {
    if (isChecked || countSelected() === 0) return;
    isChecked = true;

    var hit = 0, extra = 0, missed = 0;
    options.forEach(function (opt) {
      var correct = opt.getAttribute('data-correct') === '1';
      var selected = opt.classList.contains('is-selected');
      opt.classList.remove('is-selected');
      if (selected && correct) { opt.classList.add('is-correct'); hit++; }
      else if (selected && !correct) { opt.classList.add('is-wrong'); extra++; }
      else if (!selected && correct) { opt.classList.add('is-missed'); missed++; }
      opt.disabled = true;
    });

    btnCheck.disabled = true;
    btnReset.disabled = false;

    feedback.classList.remove('ek-feedback--ok', 'ek-feedback--err');
    var html;
    if (hit === TOTAL_CORRECT && extra === 0) {
      feedback.classList.add('ek-feedback--ok');
      html = 'Точно! Все ' + TOTAL_CORRECT + ' верных выражения найдены 🎉' +
        '<span class="qm-note">and требует, чтобы обе части были True, or — хотя бы одну, а not переворачивает результат. Ты всё это учёл.</span>';
    } else {
      feedback.classList.add('ek-feedback--err');
      html = 'Найдено ' + hit + ' из ' + TOTAL_CORRECT + ' верных, лишних: ' + extra + '.' +
        '<span class="qm-note">Помни: and даёт True, только когда обе части True; or — когда хотя бы одна; not переворачивает результат.' +
        (missed > 0 ? ' Пунктирной рамкой отмечены верные выражения, которые ты пропустил.' : '') +
        '</span>';
    }
    feedback.innerHTML = html;
    feedback.classList.add('is-on');
  });

  btnReset.addEventListener('click', function () {
    isChecked = false;
    options.forEach(function (opt) {
      opt.classList.remove('is-selected', 'is-correct', 'is-wrong', 'is-missed');
      opt.setAttribute('aria-pressed', 'false');
      opt.disabled = false;
    });
    feedback.classList.remove('is-on', 'ek-feedback--ok', 'ek-feedback--err');
    feedback.innerHTML = '';
    btnCheck.disabled = true;
    btnReset.disabled = true;
    syncControls();
  });

  syncControls();
})();

