(function(){
  'use strict';
  var root=document.getElementById('ib-true-false');
  if(!root||root.dataset.tfInit==='1')return;
  root.dataset.tfInit='1';

  var DATA=[
    {html:'<code class="tf-kw">elif</code> проверяется, только если условие выше оказалось ложным',
     answer:true,
     why:'Python идёт по каскаду сверху вниз и заглядывает в elif, только когда условие выше дало False.'},
    {html:'<code class="tf-kw">else</code> может стоять перед <code class="tf-kw">elif</code>',
     answer:false,
     why:'else всегда закрывает каскад и стоит последним — после if и всех elif.'},
    {html:'Внутри <code class="tf-kw">if</code> можно написать ещё один <code class="tf-kw">if</code> — это вложенное условие',
     answer:true,
     why:'Условие внутри условия называется вложенным, а уровни вложенности Python различает по отступам.'},
    {html:'В каскаде условий обязательно должен быть <code class="tf-kw">elif</code>',
     answer:false,
     why:'elif — необязательная ступень: каскад может состоять из одного if или из пары if и else.'}
  ];

  var stage=root.querySelector('#true-false-stage'),
      statementEl=root.querySelector('#true-false-statement'),
      btnTrue=root.querySelector('#true-false-btn-true'),
      btnFalse=root.querySelector('#true-false-btn-false'),
      feedback=root.querySelector('#true-false-feedback'),
      nextBtn=root.querySelector('#true-false-next'),
      restartBtn=root.querySelector('#true-false-restart'),
      counter=root.querySelector('#true-false-counter'),
      result=root.querySelector('#true-false-result'),
      ring=root.querySelector('#true-false-ring'),
      scoreNum=root.querySelector('#true-false-score'),
      phrase=root.querySelector('#true-false-phrase'),
      dots=root.querySelectorAll('#true-false-dots i');

  var idx=0,score=0,answered=false;

  function replay(el){
    el.classList.remove('is-anim');
    void el.offsetWidth;
    el.classList.add('is-anim');
  }

  function renderDots(){
    for(var i=0;i<dots.length;i++){
      dots[i].className=i<idx?'is-done':(i===idx?'is-on':'');
    }
    counter.textContent=Math.min(idx+1,DATA.length)+' / '+DATA.length;
  }

  function showStep(moveFocus){
    answered=false;
    statementEl.innerHTML=DATA[idx].html;
    btnTrue.disabled=false;
    btnFalse.disabled=false;
    btnTrue.classList.remove('is-correct','is-wrong');
    btnFalse.classList.remove('is-correct','is-wrong');
    feedback.className='ek-feedback';
    feedback.textContent='';
    nextBtn.hidden=true;
    result.hidden=true;
    stage.hidden=false;
    renderDots();
    replay(stage);
    if(moveFocus)btnTrue.focus();
  }

  function answer(val){
    if(answered)return;
    answered=true;
    var item=DATA[idx],ok=(val===item.answer);
    if(ok)score++;
    var chosen=val?btnTrue:btnFalse,
        other=val?btnFalse:btnTrue;
    btnTrue.disabled=true;
    btnFalse.disabled=true;
    if(ok){
      chosen.classList.add('is-correct');
    }else{
      chosen.classList.add('is-wrong');
      other.classList.add('is-correct');
    }
    feedback.className='ek-feedback is-on '+(ok?'ek-feedback--ok':'ek-feedback--err');
    feedback.textContent=(ok?'Верно! ':'Не совсем: ')+item.why;
    nextBtn.hidden=false;
    restartBtn.disabled=false;
  }

  function showResult(){
    stage.hidden=true;
    nextBtn.hidden=true;
    result.hidden=false;
    renderDots();
    scoreNum.textContent=String(score);
    ring.style.background='conic-gradient(var(--ek-green-deep) '+(score/DATA.length*100)+'%, var(--ek-gray-light) 0)';
    phrase.textContent=score===DATA.length
      ?'Огонь, ты разобрался в каскадах!'
      :(score>=2?'Неплохо, но повтори тему':'Вернись к конспекту урока');
    replay(result);
    restartBtn.focus();
  }

  btnTrue.addEventListener('click',function(){answer(true);});
  btnFalse.addEventListener('click',function(){answer(false);});
  nextBtn.addEventListener('click',function(){
    idx++;
    if(idx>=DATA.length){showResult();}else{showStep(true);}
  });
  restartBtn.addEventListener('click',function(){
    idx=0;
    score=0;
    restartBtn.disabled=true;
    showStep(true);
  });

  showStep(false);
})();

