  var root = document.getElementById('ib-code-output');
  if (!root) return;
  var options = Array.prototype.slice.call(root.querySelectorAll('.ek-option'));
  var feedback = root.querySelector('#code-output-feedback');
  var verdict = root.querySelector('#code-output-fb-verdict');
  var note = root.querySelector('#code-output-fb-note');
  var resetBtn = root.querySelector('#code-output-reset');
  var answered = false;

  function handlePick(btn){
    if (answered) return;
    answered = true;
    var isCorrect = btn.hasAttribute('data-correct');
    options.forEach(function(b){
      b.disabled = true;
      if (b.hasAttribute('data-correct')) b.classList.add('is-correct');
    });
    if (isCorrect){
      feedback.classList.add('ek-feedback--ok');
      verdict.textContent = 'Верно! Программа напечатает «Покупка невозможна».';
    } else {
      btn.classList.add('is-wrong');
      feedback.classList.add('ek-feedback--err');
      verdict.textContent = 'Пока нет. Правильный ответ — Б: «Покупка невозможна».';
    }
    note.textContent = btn.getAttribute('data-note') || '';
    feedback.classList.add('is-on');
    resetBtn.disabled = false;
  }

  options.forEach(function(btn){
    btn.addEventListener('click', function(){ handlePick(btn); });
  });

  resetBtn.addEventListener('click', function(){
    answered = false;
    options.forEach(function(b){
      b.disabled = false;
      b.classList.remove('is-selected', 'is-correct', 'is-wrong');
    });
    feedback.classList.remove('is-on', 'ek-feedback--ok', 'ek-feedback--err');
    verdict.textContent = '';
    note.textContent = '';
    resetBtn.disabled = true;
  });
})();

(function(){
  'use strict';
  var root = document.getElementById('ib-fill-blank');
  if (!root) return;

  var ANSWERS = { '1': 'elif', '2': 'else' };
  var inputs = Array.prototype.slice.call(root.querySelectorAll('.fb-blank'));
  var checkBtn = root.querySelector('#fill-blank-check');
  var resetBtn = root.querySelector('#fill-blank-reset');
  var feedback = root.querySelector('#fill-blank-feedback');
  var solved = false;

  function norm(value) { return value.trim().toLowerCase(); }

  function hideFeedback() {
    feedback.classList.remove('is-on', 'ek-feedback--ok', 'ek-feedback--err');
    feedback.textContent = '';
  }

  function showFeedback(ok, msg) {
    feedback.classList.remove('ek-feedback--ok', 'ek-feedback--err');
    feedback.classList.add('is-on', ok ? 'ek-feedback--ok' : 'ek-feedback--err');
    feedback.textContent = msg;
  }

  function shake(el) {
    el.classList.remove('is-shake');
    void el.offsetWidth;
    el.classList.add('is-shake');
  }

  function check() {
    if (solved) return;
    var allOk = true;
    var firstWrong = null;
    inputs.forEach(function (inp) {
      var ok = norm(inp.value) === ANSWERS[inp.getAttribute('data-gap')];
      inp.classList.toggle('is-correct', ok);
      inp.classList.toggle('is-wrong', !ok);
      if (!ok) {
        shake(inp);
        if (!firstWrong) firstWrong = inp;
        allOk = false;
      }
    });
    resetBtn.disabled = false;
    if (allOk) {
      solved = true;
      inputs.forEach(function (inp) { inp.disabled = true; });
      checkBtn.disabled = true;
      showFeedback(true, 'Код собран! Каскад работает 🎉');
    } else {
      showFeedback(false, 'Пока не то. Вспомни: продолжение каскада — elif, ветка «иначе» — else. Исправь и нажми «Проверить» ещё раз.');
      firstWrong.focus();
    }
  }

  inputs.forEach(function (inp) {
    inp.addEventListener('input', function () {
      if (solved) return;
      inp.classList.remove('is-correct', 'is-wrong', 'is-shake');
      resetBtn.disabled = false;
    });
    inp.addEventListener('keydown', function (e) {
      if (e.key === 'Enter') { e.preventDefault(); check(); }
    });
    inp.addEventListener('animationend', function () {
      inp.classList.remove('is-shake');
    });
  });

  checkBtn.addEventListener('click', check);

  resetBtn.addEventListener('click', function () {
    solved = false;
    inputs.forEach(function (inp) {
      inp.value = '';
      inp.disabled = false;
      inp.classList.remove('is-correct', 'is-wrong', 'is-shake');
    });
    checkBtn.disabled = false;
    hideFeedback();
    resetBtn.disabled = true;
    if (inputs.length) inputs[0].focus();
  });
})();

