(function(){
  'use strict';
  var root = document.getElementById('ib-flashcard');
  if (!root) return;
  if (root.getAttribute('data-flashcard-init') === '1') return;
  root.setAttribute('data-flashcard-init', '1');

  var cards = Array.prototype.slice.call(root.querySelectorAll('.flashcard-card'));
  var flipBtn = root.querySelector('#flashcard-flip');
  var nextBtn = root.querySelector('#flashcard-next');
  var resetBtn = root.querySelector('#flashcard-reset');
  var countEl = root.querySelector('#flashcard-count');
  var dots = Array.prototype.slice.call(root.querySelectorAll('#flashcard-dots i'));
  var total = cards.length;
  if (!total || !flipBtn || !nextBtn || !resetBtn || !countEl) return;
  var idx = 0;
  var touched = false;
  var seen = [];
  var i;
  for (i = 0; i < total; i++) { seen.push(false); }

  function isFlipped() {
    return cards[idx].classList.contains('is-flipped');
  }

  function syncFaces() {
    for (var c = 0; c < total; c++) {
      var flipped = cards[c].classList.contains('is-flipped');
      var front = cards[c].querySelector('.flashcard-front');
      var back = cards[c].querySelector('.flashcard-back');
      if (front) { front.setAttribute('aria-hidden', flipped ? 'true' : 'false'); }
      if (back) { back.setAttribute('aria-hidden', flipped ? 'false' : 'true'); }
    }
  }

  function syncUI() {
    var flipped = isFlipped();
    flipBtn.textContent = flipped ? 'Показать вопрос' : 'Показать ответ';
    flipBtn.setAttribute('aria-pressed', flipped ? 'true' : 'false');
    cards[idx].setAttribute('aria-pressed', flipped ? 'true' : 'false');
    var countText = (idx + 1) + ' / ' + total;
    if (countEl.textContent !== countText) { countEl.textContent = countText; }
    for (var d = 0; d < dots.length; d++) {
      dots[d].className = d === idx ? 'is-on' : (seen[d] ? 'is-done' : '');
    }
    nextBtn.disabled = idx === total - 1;
    resetBtn.disabled = !touched;
    syncFaces();
  }

  function flip() {
    cards[idx].classList.toggle('is-flipped');
    if (isFlipped()) { seen[idx] = true; }
    touched = true;
    syncUI();
  }

  function goNext() {
    if (idx >= total - 1) return;
    var prev = cards[idx];
    prev.classList.remove('is-active');
    prev.classList.remove('is-flipped');
    prev.setAttribute('aria-pressed', 'false');
    idx += 1;
    cards[idx].classList.add('is-active');
    touched = true;
    syncUI();
  }

  function reset() {
    for (var c = 0; c < total; c++) {
      cards[c].classList.remove('is-active');
      cards[c].classList.remove('is-flipped');
      cards[c].setAttribute('aria-pressed', 'false');
      seen[c] = false;
    }
    idx = 0;
    touched = false;
    cards[0].classList.add('is-active');
    syncUI();
  }

  for (i = 0; i < total; i++) {
    (function (card) {
      card.addEventListener('click', function () {
        if (card === cards[idx]) { flip(); }
      });
    })(cards[i]);
  }
  flipBtn.addEventListener('click', flip);
  nextBtn.addEventListener('click', goNext);
  resetBtn.addEventListener('click', reset);

  syncUI();
})();

