(function(){
  'use strict';
  var root=document.getElementById('ib-match-pairs');
  if(!root) return;
  if(root.getAttribute('data-mp-init')==='1') return;
  root.setAttribute('data-mp-init','1');

  var TOTAL=4;
  var descsCol=root.querySelector('#match-pairs-descs');
  var counter=root.querySelector('#match-pairs-count');
  var dots=root.querySelectorAll('#match-pairs-dots i');
  var feedback=root.querySelector('#match-pairs-feedback');
  var resetBtn=root.querySelector('#match-pairs-reset');
  var terms=Array.prototype.slice.call(root.querySelectorAll('.mp-term'));
  var descs=Array.prototype.slice.call(root.querySelectorAll('.mp-desc'));

  var selTerm=null;
  var selDesc=null;
  var matched=0;
  var wrongTimer=null;
  var wrongPair=[];

  function setSelected(btn,on){
    if(on){btn.classList.add('is-selected');}else{btn.classList.remove('is-selected');}
    btn.setAttribute('aria-pressed',on?'true':'false');
  }

  function clearWrong(){
    if(wrongTimer!==null){clearTimeout(wrongTimer);wrongTimer=null;}
    for(var i=0;i<wrongPair.length;i++){wrongPair[i].classList.remove('is-wrong');}
    wrongPair=[];
  }

  function updateScore(){
    counter.textContent='Собрано пар: '+matched+' из '+TOTAL;
    for(var i=0;i<dots.length;i++){
      if(i<matched){dots[i].classList.add('is-done');}else{dots[i].classList.remove('is-done');}
    }
  }

  function tryMatch(){
    if(!selTerm||!selDesc) return;
    var t=selTerm;
    var d=selDesc;
    selTerm=null;
    selDesc=null;
    setSelected(t,false);
    setSelected(d,false);
    if(t.getAttribute('data-key')===d.getAttribute('data-key')){
      t.classList.add('is-correct');
      d.classList.add('is-correct');
      t.disabled=true;
      d.disabled=true;
      matched+=1;
      updateScore();
      if(matched===TOTAL){feedback.classList.add('is-on');}
    }else{
      t.classList.add('is-wrong');
      d.classList.add('is-wrong');
      wrongPair=[t,d];
      wrongTimer=setTimeout(function(){
        wrongTimer=null;
        for(var i=0;i<wrongPair.length;i++){wrongPair[i].classList.remove('is-wrong');}
        wrongPair=[];
      },500);
    }
  }

  function onPick(btn,isTerm){
    if(btn.disabled) return;
    clearWrong();
    resetBtn.disabled=false;
    var current=isTerm?selTerm:selDesc;
    if(current===btn){
      setSelected(btn,false);
      if(isTerm){selTerm=null;}else{selDesc=null;}
      return;
    }
    if(current){setSelected(current,false);}
    setSelected(btn,true);
    if(isTerm){selTerm=btn;}else{selDesc=btn;}
    tryMatch();
  }

  function bind(list,isTerm){
    for(var i=0;i<list.length;i++){
      (function(b){
        b.addEventListener('click',function(){onPick(b,isTerm);});
      })(list[i]);
    }
  }

  function shuffleDescs(){
    var btns=Array.prototype.slice.call(descsCol.querySelectorAll('.mp-desc'));
    for(var i=btns.length-1;i>0;i--){
      var j=Math.floor(Math.random()*(i+1));
      var tmp=btns[i];
      btns[i]=btns[j];
      btns[j]=tmp;
    }
    for(var k=0;k<btns.length;k++){descsCol.appendChild(btns[k]);}
  }

  function resetAll(){
    clearWrong();
    selTerm=null;
    selDesc=null;
    matched=0;
    var all=root.querySelectorAll('.ek-option');
    for(var i=0;i<all.length;i++){
      all[i].classList.remove('is-selected','is-correct','is-wrong');
      all[i].disabled=false;
      all[i].setAttribute('aria-pressed','false');
    }
    feedback.classList.remove('is-on');
    updateScore();
    shuffleDescs();
    resetBtn.disabled=true;
  }

  bind(terms,true);
  bind(descs,false);
  resetBtn.addEventListener('click',resetAll);
  shuffleDescs();
  updateScore();
})();

