(function(){
  'use strict';
  var root = document.getElementById('ib-open-reveal');
  if (!root) return;
  if (root.getAttribute('data-or-init') === '1') return;
  root.setAttribute('data-or-init', '1');

  var toggleBtn = root.querySelector('#open-reveal-toggle');
  var resetBtn = root.querySelector('#open-reveal-reset');
  var panel = root.querySelector('#open-reveal-answer');
  if (!toggleBtn || !resetBtn || !panel) return;

  var LABEL_SHOW = 'Показать эталонный ответ';
  var LABEL_HIDE = 'Скрыть ответ';

  function isOpen(){
    return panel.classList.contains('is-open');
  }

  function open(){
    panel.classList.add('is-open');
    panel.style.maxHeight = panel.scrollHeight + 'px';
    panel.setAttribute('aria-hidden', 'false');
    toggleBtn.setAttribute('aria-expanded', 'true');
    toggleBtn.textContent = LABEL_HIDE;
  }

  function close(){
    if (panel.style.maxHeight === 'none'){
      panel.style.maxHeight = panel.scrollHeight + 'px';
      void panel.offsetHeight;
    }
    panel.classList.remove('is-open');
    panel.style.maxHeight = '0px';
    panel.setAttribute('aria-hidden', 'true');
    toggleBtn.setAttribute('aria-expanded', 'false');
    toggleBtn.textContent = LABEL_SHOW;
  }

  panel.addEventListener('transitionend', function(e){
    if (e.target === panel && e.propertyName === 'max-height' && isOpen()){
      panel.style.maxHeight = 'none';
    }
  });

  toggleBtn.addEventListener('click', function(){
    if (isOpen()){
      close();
    } else {
      open();
    }
    resetBtn.disabled = false;
  });

  resetBtn.addEventListener('click', function(){
    close();
    resetBtn.disabled = true;
    toggleBtn.focus();
  });

  close();
})();
